function Get-AnyStackHostCpuCoStop {
    <#
    .SYNOPSIS
        Gets host CPU co-stop metrics.
    .DESCRIPTION
        Queries cpu.costop.summation per host.
    .PARAMETER Server
        vCenter Server hostname or VIServer object. Uses active connection if omitted.
