            $vms = Invoke-AnyStackWithRetry -ScriptBlock { Get-View -Server $vi -ViewType VirtualMachine -Filter $filter -Property Name,Guest.ToolsVersion,Guest.ToolsVersionStatus,Runtime.PowerState }
            
